parameters.jsCode:
const body = $input.first().json;
const content = body.content[0].text;

let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  throw new Error('Claude did not return valid JSON: ' + content.substring(0, 200));
}

const required = ['title', 'summary', 'tags', 'category', 'source_type'];
const missing = required.filter(k => !(k in parsed));
if (missing.length > 0) {
  throw new Error('Claude response missing fields: ' + missing.join(', '));
}
if (!Array.isArray(parsed.tags)) {
  throw new Error('Claude response: tags must be an array');
}

parsed.title = String(parsed.title || 'Untitled').substring(0, 100);
parsed.summary = String(parsed.summary || '').substring(0, 2000);
parsed.category = String(parsed.category || 'Inbox');
parsed.source_type = String(parsed.source_type || 'thought');
parsed.tags = parsed.tags.map(t => String(t).toLowerCase().replace(/[^a-z0-9-]/g, '')).filter(Boolean).slice(0, 6);

return [{ json: parsed }];

const claudeData = $input.first().json;
const triggerData = $('Telegram Trigger').first().json;

const now = new Date();
const dateStr = now.toISOString().split('T')[0];

function slugify(text) {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\.+/g, '')
    .trim()
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .substring(0, 50);
}

const slug = slugify(claudeData.title) || 'untitled';
const filename = `${dateStr}-${slug}.md`;

const INBOX = '/opt/obsidian-vault/Inbox';
const filepath = `${INBOX}/${filename}`;
if (!filepath.startsWith(INBOX + '/')) {
  throw new Error('Path traversal detected in filename: ' + filename);
}

const tagsFormatted = claudeData.tags.map(t => `#${t}`).join(' ');
const rawMessage = triggerData.message.text || triggerData.message.caption || '(no text)';

const noteContent = `# ${claudeData.title}\n\n**Date:** ${dateStr}\n**Category:** ${claudeData.category}\n**Source:** ${claudeData.source_type}\n**Channel:** telegram\n**Tags:** ${tagsFormatted}\n\n---\n\n## Summary\n\n${claudeData.summary}\n\n---\n\n## Raw capture\n\n${rawMessage}\n`;

const binaryData = Buffer.from(noteContent, 'utf-8').toString('base64');

return [{
  json: { filename, filepath, title: claudeData.title, category: claudeData.category },
  binary: {
    data: {
      data: binaryData,
      mimeType: 'text/markdown',
      fileExtension: 'md',
      fileName: filename
    }
  }
}];

