const body = $input.first().json;
const raw = body.content[0].text;

// Strip markdown code fences if Claude wrapped the JSON
const content = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  throw new Error('Claude did not return valid JSON: ' + raw.substring(0, 200));
}

const required = ['title', 'summary', 'key_points', 'analysis', 'tags', 'topic', 'category', 'source_type'];
const missing = required.filter(k => !(k in parsed));
if (missing.length > 0) {
  throw new Error('Claude response missing fields: ' + missing.join(', '));
}
if (!Array.isArray(parsed.tags)) {
  throw new Error('Claude response: tags must be an array');
}
if (!Array.isArray(parsed.key_points)) {
  throw new Error('Claude response: key_points must be an array');
}

const VALID_CATEGORIES = new Set(['Inbox', 'Research', 'Ideas', 'Links']);
const VALID_SOURCE_TYPES = new Set(['article', 'thought', 'link', 'quote', 'task']);

if (!VALID_CATEGORIES.has(parsed.category)) {
  parsed.category = 'Inbox';
}
if (!VALID_SOURCE_TYPES.has(parsed.source_type)) {
  parsed.source_type = 'thought';
}

// Sanitise topic: lowercase slug only
parsed.topic = String(parsed.topic || 'general').toLowerCase().replace(/[^a-z0-9-]/g, '') || 'general';

// Strip ASCII control chars (0x00-0x1F, excl. \t and \n) from all string fields
function stripCtrl(s) { return String(s).replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, ''); }
parsed.title = stripCtrl(parsed.title);
parsed.summary = stripCtrl(parsed.summary);
parsed.analysis = stripCtrl(parsed.analysis);
parsed.key_points = parsed.key_points.map(stripCtrl);
parsed.tags = parsed.tags.map(t => stripCtrl(t).toLowerCase().replace(/[^a-z0-9-]/g, ''));

return [{ json: parsed }];

