const fs = require('fs');

const channel = triggerData.channel || 'telegram';
const now = new Date();
const dateStr = now.toISOString().split('T')[0];

function escapeYamlDq(s) { return String(s).replace(/\\/g, '\\\\').replace(/"/g, '\\"'); }

function slugify(text) {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\.+/g, '')
    .trim()
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .substring(0, 50);
}

// Manual path normalizer (replaces path.resolve — 'path' module disallowed in task runner)
function normalizePath(p) {
  const parts = p.split('/');
  const out = [];
  for (const part of parts) {
    if (part === '..') out.pop();
    else if (part !== '.' && part !== '') out.push(part);
  }
  return '/' + out.join('/');
}

const slug = slugify(claudeData.title) || 'untitled';
const filename = dateStr + '-' + slug + '.md';

if (!/^\d{4}-\d{2}-\d{2}-[a-z0-9-]+\.md$/.test(filename)) {
  throw new Error('Invalid filename: ' + filename);
}

const VAULT = '/opt/obsidian-vault';
const CATEGORY_FOLDERS = { Research: VAULT + '/Research', Ideas: VAULT + '/Ideas', Links: VAULT + '/Links', Inbox: VAULT + '/Inbox' };
const categoryFolder = CATEGORY_FOLDERS[claudeData.category] || (VAULT + '/Inbox');

const topicSlug = claudeData.topic || 'general';
const topicFolderName = topicSlug.charAt(0).toUpperCase() + topicSlug.slice(1);
const topicFolder = categoryFolder + '/' + topicFolderName;
const filepath = topicFolder + '/' + filename;

const resolved = normalizePath(filepath);
if (!resolved.startsWith(VAULT + '/')) {
  throw new Error('Path traversal detected: ' + filepath);
}

fs.mkdirSync(topicFolder, { recursive: true });

const tagsYaml = claudeData.tags.join(', ');
const keyPointsBullets = claudeData.key_points.map(p => '- ' + p).join('\n');

let extraFrontmatter = '';
let rawSection = '';

if (channel === 'email') {
  if (!triggerData.messageId) throw new Error('Email messageId missing from sub-workflow input');
  const subject = String(triggerData.subject || '(no subject)').replace(/[\r\n\x00-\x1f]/g, ' ');
  const fromSender = String(triggerData.from || '').replace(/[\r\n\x00-\x1f]/g, ' ').substring(0, 200);
  extraFrontmatter = '\nfrom: "' + escapeYamlDq(fromSender) + '"';
  rawSection = '**Subject:** ' + subject + '\n\n' + (triggerData.rawText || '(no body)');
} else {
  rawSection = triggerData.rawText || '(no text)';
}

const noteContent =
  '---\n' +
  'title: "' + escapeYamlDq(claudeData.title) + '"\n' +
  'date: ' + dateStr + '\n' +
  'category: ' + claudeData.category + '\n' +
  'topic: ' + topicSlug + '\n' +
  'source: ' + claudeData.source_type + '\n' +
  'channel: ' + channel + extraFrontmatter + '\n' +
  'tags: [' + tagsYaml + ']\n' +
  '---\n\n' +
  '## Summary\n\n' + claudeData.summary + '\n\n' +
  keyPointsBullets + '\n\n' +
  '## Analysis\n\n' + claudeData.analysis + '\n\n' +
  '---\n\n' +
  '## Raw capture\n\n' + rawSection + '\n';

return [{ json: { filename, filepath: resolved, noteContent, title: claudeData.title, category: claudeData.category, topic: topicSlug } }];

const { filepath, noteContent } = $input.first().json;
const fs = require('fs');
fs.writeFileSync(filepath, noteContent, 'utf-8');
return $input.all();

// Check waking hours in Europe/Amsterdam timezone
const now = new Date();
const formatter = new Intl.DateTimeFormat('nl-NL', {
  timeZone: 'Europe/Amsterdam',
  hour: 'numeric',
  hour12: false
});
const amsterdamHour = parseInt(formatter.format(now), 10);

if (amsterdamHour < 7 || amsterdamHour >= 23) {
  // Outside waking hours (07:00-23:00) — skip all checks
  return [];
}

// Get workflows from API response
const response = $input.first().json;
const workflows = response.data || [];

// Exclude this health-check workflow itself (by UUID and name for robustness)
// Assumes ≤10 active workflows per page (homelab). Pagination not implemented.
const SELF_ID   = 'b5717a69-a46c-484e-ac44-aa65e143acfd';
const SELF_NAME = 'n8n Health Check — Idle Workflow Alert';
return workflows
  .filter(w => w.id !== SELF_ID && w.name !== SELF_NAME)
  .map(w => ({ json: { id: w.id, name: w.name } }));

const TWO_HOURS_MS = 2 * 60 * 60 * 1000;
const now = Date.now();
const execItems = $input.all();
const wfItems = $('Time Check + Split').all();
const idle = [];

// Guard: if counts differ, pairing is unsafe — stop chain (visible in n8n execution log)
if (execItems.length !== wfItems.length) {
  return [];
}

for (let i = 0; i < execItems.length; i++) {
  const execResponse = execItems[i].json;
  const wf = wfItems[i].json;

  // Skip if HTTP error
  if (execResponse.error || !execResponse.data) continue;

  const executions = execResponse.data;

  // Per spec: no alert for workflows with no executions yet
  if (executions.length === 0) continue;

  const lastExec = executions[0];
  const lastRunRaw = lastExec.startedAt || lastExec.stoppedAt;
  if (!lastRunRaw) continue;

  const lastRunTime = new Date(lastRunRaw).getTime();
  const idleMs = now - lastRunTime;

  if (idleMs > TWO_HOURS_MS) {
    idle.push({
      name: wf.name || ('Workflow ' + wf.id),
      id: wf.id,
      lastRun: lastExec.startedAt,
      idleMinutes: Math.round(idleMs / 60000)
    });
  }
}

if (idle.length === 0) return [];

return [{ json: { idleWorkflows: idle } }];

const idle = $input.first().json.idleWorkflows;
const lines = idle.map(function(w) {
  const h = Math.floor(w.idleMinutes / 60);
  const m = w.idleMinutes % 60;
  const timeStr = h > 0 ? (h + 'h ' + m + 'm') : (m + 'm');
  let lastRunStr = 'unknown';
  if (w.lastRun) {
    lastRunStr = new Date(w.lastRun).toLocaleTimeString('nl-NL', {
      timeZone: 'Europe/Amsterdam',
      hour: '2-digit',
      minute: '2-digit'
    });
  }
  return '\u2022 ' + w.name + ' \u2014 idle ' + timeStr + ' (last: ' + lastRunStr + ')';
});
const count = idle.length;
const text = '\u26a0\ufe0f n8n health check: ' + count + ' workflow' + (count > 1 ? 's' : '') + ' idle >2h\n\n' + lines.join('\n');
return [{ json: { text: text } }];
